 35→/** Allows specification of the Question and Answer format of a card template in the Card Browser
 36→ * This is known as "Browser Appearance" in Anki
 37→ * We do not allow the user to change fonts as Android only has a handful
 38→ * We do not allow the user to change the font size as this can be done in the Appearance settings.
 39→ */
 40→class CardTemplateBrowserAppearanceEditor : AnkiActivity() {
 41→    private lateinit var questionEditText: EditText
 42→    private lateinit var answerEditText: EditText
 43→    override fun onCreate(savedInstanceState: Bundle?) {
 44→        if (showedActivityFailedScreen(savedInstanceState)) {
 45→            return
 46→        }
 47→        super.onCreate(savedInstanceState)
 48→        val bundle = savedInstanceState ?: intent.extras
 49→        if (bundle == null) {
 50→            UIUtils.showThemedToast(this, getString(R.string.card_template_editor_card_browser_appearance_failed), true)
 51→            finish()
 52→            return
 53→        }
 54→        initializeUiFromBundle(bundle)
 55→    }
 56→
 57→    override fun onCreateOptionsMenu(menu: Menu): Boolean {
 58→        menuInflater.inflate(R.menu.card_template_browser_appearance_editor, menu)
 59→        return true
 60→    }
 61→
 62→    override fun onOptionsItemSelected(item: MenuItem): Boolean {
 63→        when (item.itemId) {
 64→            R.id.action_confirm -> {
 65→                Timber.i("Save pressed")
 66→                saveAndExit()
 67→                return true
 68→            }
 69→            R.id.action_restore_default -> {
 70→                Timber.i("Restore Default pressed")
 71→                showRestoreDefaultDialog()
 72→                return true
 73→            }
 74→            android.R.id.home -> {
 75→                Timber.i("Back Pressed")
 76→                closeWithDiscardWarning()
 77→                return true
 78→            }
 79→            else -> {}
 80→        }
 81→        return super.onOptionsItemSelected(item)
 82→    }
 83→
 84→    @Suppress("DEPRECATION", "Deprecated in API34+dependencies for predictive back feature")
 85→    override fun onBackPressed() {
 86→        Timber.i("Back Button Pressed")
 87→        super.onBackPressed()
 88→        closeWithDiscardWarning()
 89→    }
 90→
 91→    private fun closeWithDiscardWarning() {
 92→        if (hasChanges()) {
 93→            Timber.i("Changes detected - displaying discard warning dialog")
 94→            showDiscardChangesDialog()
 95→        } else {
 96→            discardChangesAndClose()
 97→        }
 98→    }
 99→
100→    private fun showDiscardChangesDialog() {
101→        DiscardChangesDialog.showDialog(this, ::discardChangesAndClose)
102→    }
103→
104→    private fun showRestoreDefaultDialog() {
105→        AlertDialog.Builder(this).show {
106→            positiveButton(R.string.dialog_ok) {
107→                restoreDefaultAndClose()
108→            }
109→            negativeButton(R.string.dialog_cancel)
110→            message(R.string.card_template_browser_appearance_restore_default_dialog)
111→        }
112→    }
113→
114→    public override fun onSaveInstanceState(outState: Bundle) {
115→        outState.putString(INTENT_QUESTION_FORMAT, questionFormat)
116→        outState.putString(INTENT_ANSWER_FORMAT, answerFormat)
117→        super.onSaveInstanceState(outState)
118→    }
119→
120→    private fun initializeUiFromBundle(bundle: Bundle) {
121→        setContentView(R.layout.card_browser_appearance)
122→
123→        questionEditText = findViewById(R.id.question_format)
124→        questionEditText.setText(bundle.getString(INTENT_QUESTION_FORMAT))
125→
126→        answerEditText = findViewById(R.id.answer_format)
127→        answerEditText.setText(bundle.getString(INTENT_ANSWER_FORMAT))
128→
129→        enableToolbar()
130→        setTitle(R.string.card_template_browser_appearance_title)
131→    }
132→
133→    private fun answerHasChanged(intent: Intent): Boolean {
134→        return intent.getStringExtra(INTENT_ANSWER_FORMAT) != answerFormat
135→    }
136→
137→    private fun questionHasChanged(intent: Intent): Boolean {
138→        return intent.getStringExtra(INTENT_QUESTION_FORMAT) != questionFormat
139→    }
140→
141→    private val questionFormat: String
142→        get() = getTextValue(questionEditText)
143→    private val answerFormat: String
144→        get() = getTextValue(answerEditText)
145→
146→    private fun getTextValue(editText: EditText): String {
147→        return editText.text.toString()
148→    }
149→
150→    private fun restoreDefaultAndClose() {
151→        Timber.i("Restoring Default and Closing")
152→        questionEditText.setText(VALUE_USE_DEFAULT)
153→        answerEditText.setText(VALUE_USE_DEFAULT)
154→        saveAndExit()
155→    }
156→
157→    private fun discardChangesAndClose() {
158→        Timber.i("Closing and discarding changes")
159→        setResult(RESULT_CANCELED)
160→        finish()
161→    }
162→
163→    private fun saveAndExit() {
164→        Timber.i("Save and Exit")
165→        val data = Intent().apply {
166→            putExtra(INTENT_QUESTION_FORMAT, questionFormat)
167→            putExtra(INTENT_ANSWER_FORMAT, answerFormat)
168→        }
169→        setResult(RESULT_OK, data)
170→        finish()
171→    }
172→
173→    private fun hasChanges(): Boolean {
174→        return try {
175→            questionHasChanged(intent) || answerHasChanged(intent)
176→        } catch (e: Exception) {
177→            Timber.w(e, "Failed to detect changes. Assuming true")
178→            true
179→        }
180→    }
181→
182→    class Result private constructor(question: String?, answer: String?) {
183→        val question: String = question ?: VALUE_USE_DEFAULT
184→        val answer: String = answer ?: VALUE_USE_DEFAULT
185→
186→        fun applyTo(template: JSONObject) {
187→            template.put("bqfmt", question)
188→            template.put("bafmt", answer)
189→        }
190→
191→        companion object {
192→            @Contract("null -> null")
193→            fun fromIntent(intent: Intent?): Result? {
194→                return if (intent == null) {
195→                    null
196→                } else {
197→                    try {
198→                        val question = intent.getStringExtra(INTENT_QUESTION_FORMAT)
199→                        val answer = intent.getStringExtra(INTENT_ANSWER_FORMAT)
200→                        Result(question, answer)
201→                    } catch (e: Exception) {
202→                        Timber.w(e, "Could not read result from intent")
203→                        null
204→                    }
205→                }
206→            }
207→        }
208→    }
209→
210→    companion object {
211→        const val INTENT_QUESTION_FORMAT = "bqfmt"
212→        const val INTENT_ANSWER_FORMAT = "bafmt"
213→
214→        /** Specified the card browser should use the default template formatter  */
215→        const val VALUE_USE_DEFAULT = ""
216→
217→        @CheckResult
218→        fun getIntentFromTemplate(context: Context, template: JSONObject): Intent {
219→            val browserQuestionTemplate = template.getString("bqfmt")
220→            val browserAnswerTemplate = template.getString("bafmt")
221→            return getIntent(context, browserQuestionTemplate, browserAnswerTemplate)
222→        }
223→
224→        @CheckResult
225→        fun getIntent(context: Context, questionFormat: String, answerFormat: String): Intent {
226→            return Intent(context, CardTemplateBrowserAppearanceEditor::class.java).apply {
227→                putExtra(INTENT_QUESTION_FORMAT, questionFormat)
228→                putExtra(INTENT_ANSWER_FORMAT, answerFormat)
229→            }
230→        }
231→    }
232→}
